import React from 'react';
import { FontAwesomeIcon } from '@fortawesome/react-fontawesome';
import { faRocket, faShieldHalved, faLightbulb } from '@fortawesome/free-solid-svg-icons';
import './App.css';

// Box bileşeni artık className alıyor
const Box = ({ icon, title, items, cardClass }) => (
  <div className={`card ${cardClass}`}>
    <div className="icon-wrapper">
      <FontAwesomeIcon icon={icon} />
    </div>
    <h2 className="card-title">{title}</h2>
    <ul className="card-list">
      {items.map((item, index) => (
        <li key={index}>{item}</li>
      ))}
    </ul>
  </div>
);

function App() {
  const data = [
    {
      title: "Strateji",
      icon: faLightbulb,
      class: "card-strategy", // CSS'teki rengi belirleyen sınıf
      items: ["Pazar Analizi", "Yol Haritası", "Rakip Takibi"]
    },
    {
      title: "Geliştirme",
      icon: faRocket,
      class: "card-dev",
      items: ["Performans", "Modern UI/UX", "Hızlı Dağıtım"]
    },
    {
      title: "Güvenlik",
      icon: faShieldHalved,
      class: "card-security",
      items: ["Veri Koruma", "SSL Sertifikası", "Uçtan Uca Şifreleme"]
    }
  ];

  return (
    <div className="container">
      <div className="box-wrapper">
        {data.map((box, index) => (
          <Box 
            key={index}
            title={box.title}
            icon={box.icon}
            cardClass={box.class}
            items={box.items}
          />
        ))}
      </div>
    </div>
  );
}

export default App;
